import { describe, it, expect } from "vitest";
import { generateQuote, processClaim } from "./claim-office.js";

describe("MHPCO Claim Office - Quote", () => {
  it.todo("should return base premium for a single sword");
  it.todo("should return base premium for a single amulet");
  it.todo("should return base premium for a single staff");
  it.todo("should return base premium for a single potion");
  it.todo("should return base premium for a single component");
  it.todo("should return sum of base premiums for two different items");
  it.todo("should apply block discount when 3 alike components are insured");
  it.todo("should apply cursed item surcharge of 50% on the item base premium");
  it.todo("should apply highly enchanted surcharge of 30% when enchantment >= 5");
  it.todo("should apply loyalty discount of 20% for customer with >= 2 years");
  it.todo("should apply first insurance surcharge of 10% on policy base premium");
  it.todo("should apply follow-up contract discount of 15% on policy base premium");
  it.todo("should add processing fee of 5 G at the end");
  it.todo("should apply ceiling rounding to premium");
});

describe("MHPCO Claim Office - Claim", () => {
  it.todo("should return payout equal to damage minus deductible for a basic item");
  it.todo("should return zero payout when damage is less than or equal to deductible");
  it.todo("should apply 50% payout rule when item enchantment >= 8");
  it.todo("should apply full reimbursement for dragon material item");
  it.todo("should use 50% rule when both dragon material and enchantment >= 8 apply");
  it.todo("should reduce remaining cap with each claim payout");
  it.todo("should cap total payout at 2x total insurance sum");
  it.todo("should apply floor rounding to payout");
});

describe("MHPCO Claim Office - Error Conditions", () => {
  it.todo("should reject quote with unknown item type");
  it.todo("should reject claim for item not in policy");
  it.todo("should reject claim with negative damage amount");
  it.todo("should reject entire claim when damage entries exceed insured count for that type");
});
